+        rdb_encode_length(&mut encoded, 1);
+        encoded.push(RDB_OPCODE_EOF);
+        append_rdb_checksum(&mut encoded);
+
+        let err = decode_rdb_prefix(&encoded).expect_err("dangling expiry must fail");
